const body = ($input.first() && $input.first().json && $input.first().json.body) || {};
const client = String(body.client || '').trim();
if (!client) throw new Error('client required');
const items = Array.isArray(body.items) ? body.items : [];
if (items.length === 0) throw new Error('items[] required');
const sheetName = 'Samples_' + client;
const now = new Date().toISOString();
return items.map(it => {
  const id = String(it.id || '').trim();
  if (!id) throw new Error('every item needs an id');
  const order_index = Number(it.order_index);
  if (!Number.isFinite(order_index)) throw new Error('every item needs a numeric order_index');
  return { json: { id, order_index: String(order_index), updated_at: now, _sheetName: sheetName, _client: client } };
});

const j = $input.item.json;
const out = {};
for (const k of Object.keys(j)) { if (k.charAt(0) === '_') continue; out[k] = j[k]; }
return { json: out };
